<?php namespace App\Repositories\Timetable;use App\Repositories\BaseRepository;use App\Models\Timetable\SubstitutionRequest;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class SubstitutionRequestRepository extends BaseRepository{    public function __construct(SubstitutionRequest $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByFromTeacher(int $employeeId): Collection    {        return $this->findByField('from_employee_id', $employeeId);    }    public function findByToTeacher(int $employeeId): Collection    {        return $this->findByField('to_employee_id', $employeeId);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getPendingRequests(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function getByDate(string $date): Collection    {        return $this->query()->whereDate('date', $date)->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('date', [$startDate, $endDate])->get();    }    public function approve(int $id): bool    {        return $this->update($id, ['status' => 'approved', 'approved_at' => now()]);    }    public function reject(int $id): bool    {        return $this->update($id, ['status' => 'rejected']);    }    public function getSubstitutionHistory(int $employeeId): Collection    {        return $this->query()->where(function ($q) use ($employeeId) {                $q->where('from_employee_id', $employeeId)->orWhere('to_employee_id', $employeeId);            })->orderBy('created_at', 'desc')->get();    }}